"""
Table recognition model — uses Vision LLM (via OpenRouter) instead of
RapidTable for table structure + content extraction.

Keeps the same predict() interface so the rest of the MinerU pipeline
is unaffected.
"""
import base64
import cv2
import numpy as np
from loguru import logger

from magic_pdf.model.sub_modules.ocr.paddleocr2pytorch.vision_llm_ocr import (
    _call_openrouter,
)


_TABLE_PROMPT = """\
Extract the table from this image and return it as a clean HTML table.

Rules:
- Return ONLY an HTML <table> element, nothing else.
- Each row becomes a <tr>, each cell a <td> (use <th> for header cells).
- If a cell spans multiple columns or rows, use colspan/rowspan attributes.
- Preserve all text in every cell exactly as it appears.
- Use <thead> and <tbody> for semantic grouping when headers are present.

Formatting rules:
- Use inline CSS styles on elements for visual formatting.
- Column widths: use PERCENTAGES (e.g., style="width: 25%"), never fixed pixel widths.
- If the source has colored/shaded rows or columns, preserve with background-color.
- Reproduce the border pattern from the source document:
  - Fully bordered → border on cells
  - No visible borders → no border CSS
  - Partial borders → selective border-top/border-bottom/border-left/border-right
- Allowed CSS: width (%), min-width, background-color, border, border-top, border-bottom, border-left, border-right, border-collapse, text-align, vertical-align, padding
- Do NOT use: font-family, font-size, color, position, float, display, margin, !important, class, id, or <style> blocks.

- Do NOT wrap in <html> or <body> tags.
- Do NOT include any explanation, just the HTML.
"""


class RapidTableModel(object):
    """Drop-in replacement: uses Vision LLM for table HTML extraction."""

    def __init__(self, ocr_engine, table_sub_model_name='slanet_plus'):
        # ocr_engine kept for interface compatibility but unused for tables
        self.ocr_engine = ocr_engine
        logger.info('[VisionLLM] Table model initialised (OpenRouter vision)')

    def predict(self, image):
        """
        Extract table HTML from an image using Vision LLM.

        Args:
            image: PIL Image or numpy array (RGB) of the table region.

        Returns:
            (html_code, table_cell_bboxes, logic_points, elapse)
            — same interface as original RapidTableModel.
            table_cell_bboxes and logic_points are empty (not needed downstream).
        """
        import time
        t0 = time.time()

        try:
            # Convert to BGR numpy for encoding
            img = np.asarray(image)
            if len(img.shape) == 3 and img.shape[2] == 3:
                bgr = cv2.cvtColor(img, cv2.COLOR_RGB2BGR)
            else:
                bgr = img

            h, w = bgr.shape[:2]
            if h < 10 or w < 10:
                return None, None, None, None

            # Downscale large table images
            max_dim = 2048
            if max(h, w) > max_dim:
                scale = max_dim / max(h, w)
                bgr = cv2.resize(
                    bgr, (int(w * scale), int(h * scale)),
                    interpolation=cv2.INTER_AREA,
                )

            success, buf = cv2.imencode(
                '.jpg', bgr, [cv2.IMWRITE_JPEG_QUALITY, 90]
            )
            if not success:
                return None, None, None, None

            image_b64 = base64.b64encode(buf).decode('ascii')
            raw = _call_openrouter(image_b64, _TABLE_PROMPT, json_mode=False, task="ocr")

            html = self._clean_html(raw)
            elapse = time.time() - t0

            if html:
                logger.debug(
                    f'[VisionLLM] Table extracted ({len(html)} chars, {elapse:.1f}s)'
                )
                return html, [], [], elapse
            else:
                return None, None, None, None

        except Exception as e:
            import traceback
            logger.warning(f'[VisionLLM] Table extraction failed: {e}')
            traceback.print_exc()
            return None, None, None, None

    @staticmethod
    def _clean_html(raw: str) -> str:
        """Strip markdown fences and wrapper tags from LLM response."""
        raw = raw.strip()
        # Strip markdown fences
        if raw.startswith('```'):
            raw = raw.split('\n', 1)[-1]
            if raw.endswith('```'):
                raw = raw[:-3]
            raw = raw.strip()
        # Remove <html><body> wrapper if model added it
        raw = raw.replace('<html>', '').replace('</html>', '')
        raw = raw.replace('<body>', '').replace('</body>', '')
        raw = raw.strip()
        if '<table' in raw.lower():
            return raw
        return ''
